<script>
import { mapActions } from 'vuex'

export default {
  name: 'HomeView',
  components: {
    // HeaderComp,
    // FooterComp
  },
  data () {
    return {
      indicators_cards: []
    }
  },
  methods: {
    ...mapActions('S20242030', [
      'loadData'
    ])
  },
  async created () {
    document.title = '¿Qué es el SIEPI? | Sistema de Información y Estadística sobre los Pueblos y Comunidades Indígenas'

    const cards = await this.loadData('20192024/json/indicators.cards.json')

    await cards.sort((a, b) => {
      if (a.title < b.title) { return -1 }
      if (a.title > b.title) { return 1 }
      return 0
    })

    this.indicators_cards = cards
  }
}
</script>
